ssh -o StrictHostKeyChecking=no -i ~/.ssh/key.pem ubuntu@ec2-100-30-41-157.compute-1.amazonaws.com "cd /var/www/html && php artisan tinker --execute='\$groups = \Illuminate\Support\Facades\DB::table(\"group_user\")->select(\"group_id\")->distinct()->pluck(\"group_id\"); foreach(\$groups as \$gid) { \$members = \Illuminate\Support\Facades\DB::table(\"group_user\")->where(\"group_id\", \$gid)->get(); foreach(\$members as \$m) { \$points = \Illuminate\Support\Facades\DB::table(\"answers\")->join(\"questions\", \"answers.question_id\", \"=\", \"questions.id\")->where(\"questions.group_id\", \$gid)->where(\"answers.user_id\", \$m->user_id)->sum(\"answers.points_earned\"); \Illuminate\Support\Facades\DB::table(\"group_user\")->where(\"id\", \$m->id)->update([\"points\" => \$points]); } echo \"Updated group {\$gid}\n\"; } echo \"All points recalculated!\n\";'"
